pub fn register_provider<T: LanguageModelProvider + LanguageModelProviderState>(
    &mut self,
    provider: Arc<T>,
    cx: &mut Context<Self>,
) {
    let subscription = provider.subscribe(cx, {
        let id = id.clone();
        move |_, cx| {
            cx.emit(Event::ProviderStateChanged(id.clone()));
        }
    });
    self.providers.insert(id.clone(), provider);
    cx.emit(Event::AddedProvider(id));
}

pub fn visible_providers(&self) -> Vec<Arc<dyn LanguageModelProvider>> {
    self.providers().into_iter().filter(|provider| {
        if let Some(hiding_fn) = &self.builtin_provider_hiding_fn {
            for extension_id in &self.installed_llm_extension_ids {
                if let Some(hidden_provider_id) = hiding_fn(extension_id) {
                    if provider.id().0 == hidden_provider_id { return false; }
                }
            }
        }
        true
    }).collect()
}

pub struct ConnectionState {
    outgoing_tx: mpsc::UnboundedSender<Message>,
    next_message_id: Arc<AtomicU32>,
    response_channels: Arc<Mutex<Option<HashMap<u32, oneshot::Sender<(proto::Envelope, std::time::Instant, oneshot::Sender<()>)>>>>>,
    stream_response_channels: Arc<Mutex<Option<HashMap<u32, mpsc::UnboundedSender<(Result<proto::Envelope>, oneshot::Sender<()>)>>>>>,
}

let _end_connection = util::defer(|| {
    response_channels.lock().take();
    if let Some(channels) = stream_response_channels.lock().take() {
        for channel in channels.values() {
            let _ = channel.unbounded_send((Err(anyhow!("connection closed")), oneshot::channel().0));
        }
    }
});

if let Some(responding_to) = incoming.responding_to {
    let response_channel = response_channels.lock().as_mut()?.remove(&responding_to);
    let stream_response_channel = stream_response_channels.lock().as_ref()?.get(&responding_to).cloned();

    if let Some(tx) = response_channel {
        let requester_resumed = oneshot::channel();
        tx.send((incoming, received_at, requester_resumed.0));
        let _ = requester_resumed.1.await;
    } else if let Some(tx) = stream_response_channel {
        let requester_resumed = oneshot::channel();
        tx.unbounded_send((Ok(incoming), requester_resumed.0));
        let _ = requester_resumed.1.await;
    }
}

