pub fn request<R: lsp_types::request::Request>(
    &self,
    params: R::Params,
) -> impl 'static + Future<Output = Result<R::Result>> {
    let id = self.next_id.fetch_add(1, SeqCst);
    let request = Request {
        jsonrpc: JSON_RPC_VERSION,
        id: RequestId::Int(id),
        method: R::METHOD,
        params,
    };

    let (tx, rx) = oneshot::channel();
    let handle_response = self.response_handlers.lock().as_mut()?.insert(
        RequestId::Int(id),
        Box::new(move |result| { tx.send(result).ok(); }),
    );
}

