pub fn initialize(
    mut self,
    params: InitializeParams,
    configuration: Arc<DidChangeConfigurationParams>,
    cx: &mut AsyncApp,
) -> Task<Result<AdapterServerCapabilities>> {
    cx.spawn(|_| async move {
        let response = self.request_internal::<lsp_types::request::Initialize>(params, timeout, &mut cx).await?;

        if let Some(info) = response.server_info {
            self.version = Some(info.version.unwrap_or_default().into());
        }

        *self.capabilities.write() = response.capabilities.clone();
        self.notify::<lsp_types::notification::Initialized>(InitializedParams {})?;

        Ok(AdapterServerCapabilities {
            server_capabilities: response.capabilities,
            code_action_kinds: self.code_action_kinds.clone(),
        })
    })
}

