fn register_setting_internal(&mut self, registered_setting: &RegisteredSetting) {
    let setting_value = entry.or_insert((registered_setting.settings_value)());
    let value = (registered_setting.from_settings)(&self.merged_settings);
    setting_value.set_global_value(value);
}

fn recompute_values(&mut self, changed_local_keys: Option<BTreeSet<(WorktreeId, Arc<RelPath>)>>, cx: &mut App) {
    let mut merged_settings = self.default_settings.as_ref().clone();
    if let Some(extension_settings) = &self.extension_settings {
        merged_settings.merge_from(extension_settings);
    }
    if let Some(server_settings) = &self.server_settings {
        merged_settings.merge_from(server_settings);
    }
    if let Some(user_settings) = &self.user_settings {
        merged_settings.merge_from(user_settings);
    }
    self.merged_settings = merged_settings.into();

    for setting_value in self.setting_values.values_mut() {
        let value = setting_value.from_settings(&self.merged_settings);
        setting_value.set_global_value(value);
    }

    for ((worktree_id, path), local_settings) in &self.local_settings {
        let mut merged = self.merged_settings.as_ref().clone();
        merged.merge_from(local_settings);
        for setting_value in self.setting_values.values_mut() {
            let value = setting_value.from_settings(&merged);
            setting_value.set_local_value(*worktree_id, path.clone(), value);
        }
    }
}

response_channels: Arc<Mutex<Option<HashMap<u32, oneshot::Sender<(proto::Envelope, std::time::Instant, oneshot::Sender<()>)>>>>>,
stream_response_channels: Arc<Mutex<Option<HashMap<u32, mpsc::UnboundedSender<(Result<proto::Envelope>, oneshot::Sender<()>)>>>>>,

let incoming_rx = incoming_rx.filter_map(move |(incoming, received_at)| {
    async move {
        if let Some(responding_to) = incoming.responding_to {
            let response_channel = response_channels.lock().as_mut()?.remove(&responding_to);

            if let Some(tx) = response_channel {
                let requester_resumed = oneshot::channel();
                if let Err(error) = tx.send((incoming, received_at, requester_resumed.0)) {
                    tracing::trace!("incoming response: request future dropped");
                }

                tracing::trace!("incoming response: waiting to resume requester");
                let _ = requester_resumed.1.await;
                tracing::trace!("incoming response: requester resumed");
            } else if let Some(tx) = stream_response_channel {
                let requester_resumed = oneshot::channel();
                if let Err(error) = tx.unbounded_send((Ok(incoming), requester_resumed.0)) {
                    tracing::debug!("incoming stream response: request future dropped");
                }

                tracing::debug!("incoming stream response: waiting to resume requester");
                let _ = requester_resumed.1.await;
                tracing::debug!("incoming stream response: requester resumed");
            }
            None
        }
    }
});

