    language_server_id: LanguageServerName,
    language_name: LanguageName,
    worktree: Arc<dyn WorktreeDelegate>,
) -> Result<Command> {
    self.call(|extension, store| {
        async move {
            let resource = store.data_mut().table().push(worktree)?;
            let command = extension
                .call_language_server_command(
                    store,
                    &language_server_id,
                    &language_name,
                    resource,
                )
                .await?
                .map_err(|err| store.data().extension_error(err))?;
            Ok(command.into())
        }
        .boxed()
    })
    .await?
}

type IoHandler = Box<dyn Send + FnMut(IoKind, &str)>;

#[derive(Debug, Clone, Copy)]
pub enum IoKind {
    StdOut,
    StdIn,
    StdErr,
}

io_handlers: Arc<Mutex<HashMap<i32, IoHandler>>>,

pub enum Subscription {
    Notification {
        method: &'static str,
        notification_handlers: Option<Arc<Mutex<HashMap<&'static str, NotificationHandler>>>>,
    },
    Io {
        id: i32,
        io_handlers: Option<Weak<Mutex<HashMap<i32, IoHandler>>>>,
    },
}

let stderr_input_task = stderr.map(|stderr| {
    let io_handlers = io_handlers.clone();
    let stderr_captures = stderr_capture.clone();
    cx.background_spawn(async move {
        Self::handle_stderr(stderr, io_handlers, stderr_captures).log_err().await
    })
});

async fn handle_stderr<Stderr>(
    stderr: Stderr,
    io_handlers: Arc<Mutex<HashMap<i32, IoHandler>>>,
    stderr_capture: Arc<Mutex<Option<String>>>,
) -> anyhow::Result<()> {
    let mut stderr = BufReader::new(stderr);
    let mut buffer = String::new();

    loop {
        buffer.clear();
        if stderr.read_line(&mut buffer).await? == 0 {
            return Ok(());
        }

        if let Some(capture) = stderr_capture.lock().as_mut() {
            capture.push_str(&buffer);
        }

        for handler in io_handlers.lock().values_mut() {
            handler(IoKind::StdErr, &buffer);
        }
    }
}

pub fn on_io(&self, f: impl 'static + Send + FnMut(IoKind, &str)) -> Subscription {
    let id = self.next_id.fetch_add(1, SeqCst);
    let mut io_handlers = self.io_handlers.lock();
    io_handlers.insert(id, Box::new(f));
    Subscription::Io {
        id,
        io_handlers: Some(Arc::downgrade(&self.io_handlers)),
    }
}

type RequestIds = Arc<
    Mutex<
        HashMap<
            LspRequestId,
            oneshot::Sender<
                Result<
                    Option<TypedEnvelope<Vec<proto::ProtoLspResponse<Box<dyn AnyTypedEnvelope>>>>>,
                >,
            >,
        >,
    >,
>;

static NEXT_LSP_REQUEST_ID: OnceLock<Arc<AtomicU64>> = OnceLock::new();
static REQUEST_IDS: OnceLock<RequestIds> = OnceLock::new();

struct State {
    client: Arc<dyn ProtoClient>,
    next_lsp_request_id: Arc<AtomicU64>,
    request_ids: RequestIds,
}

pub fn request_lsp<T>(
    &self,
    project_id: u64,
    server_id: Option<u64>,
    timeout: Duration,
    executor: BackgroundExecutor,
    request: T,
) -> impl Future<Output = Result<Option<TypedEnvelope<Vec<proto::ProtoLspResponse<T::Response>>>>>> + use<T>
where
    T: LspRequestMessage,
{
    let new_id = LspRequestId(
        self.0.next_lsp_request_id.fetch_add(1, atomic::Ordering::Acquire),
    );
    let (tx, rx) = oneshot::channel();
    self.0.request_ids.lock().insert(new_id, tx);

    let query = proto::LspQuery {
        project_id,
        server_id,
        lsp_request_id: new_id.0,
        request: Some(request.to_proto_query()),
    };
    let request = self.request(query);
    let request_ids = self.0.request_ids.clone();

    async move {
        match request.await {
            Ok(_request_enqueued) => {}
            Err(e) => {
                request_ids.lock().remove(&new_id);
                return Err(e).context("sending LSP proto request");
            }
        }

        let response = rx.with_timeout(timeout, &executor).await;
        request_ids.lock().remove(&new_id);
        match response {
            Ok(Ok(response)) => Ok(response.transpose()?),
            Err(_cancelled_due_timeout) => Ok(None),
            Ok(Err(_channel_dropped)) => Ok(None),
        }
    }
}

pub fn handle_lsp_response(&self, mut envelope: TypedEnvelope<proto::LspQueryResponse>) {
    let request_id = LspRequestId(envelope.payload.lsp_request_id);
    let mut response_senders = self.0.request_ids.lock();
    if let Some(tx) = response_senders.remove(&request_id) {
        let responses = envelope.payload.responses.drain(..).collect::<Vec<_>>();
        tx.send(Ok(Some(proto::TypedEnvelope {
            sender_id: envelope.sender_id,
            original_sender_id: envelope.original_sender_id,
            message_id: envelope.message_id,
            received_at: envelope.received_at,
            payload: responses.into_iter().filter_map(|response| {
                let server_id = response.server_id;
                let response = match response.response? { ... };
                Some(proto::ProtoLspResponse { server_id, response })
            }).collect(),
        }))).ok();
    }
}

