pub struct CapabilityGranter {
    granted_capabilities: Vec<ExtensionCapability>,
    manifest: Arc<ExtensionManifest>,
}

impl CapabilityGranter {
    pub fn new(
        granted_capabilities: Vec<ExtensionCapability>,
        manifest: Arc<ExtensionManifest>,
    ) -> Self {
        Self { granted_capabilities, manifest }
    }

    pub fn grant_exec(&self, desired_command: &str, desired_args: &[String]) -> Result<()> {
        let is_allowed = self
            .granted_capabilities
            .iter()
            .any(|capability| match capability {
                ExtensionCapability::ProcessExec(capability) => {
                    capability.allows(desired_command, desired_args)
                }
                _ => false,
            });

        if !is_allowed {
            bail!(
                "Extension {} does not have permission to run command '{}' with args {:?}",
                self.manifest.id,
                desired_command,
                desired_args
            );
        }
        Ok(())
    }

    pub fn grant_download(&self, desired_url: &Url) -> Result<()> {
        let is_allowed = self
            .granted_capabilities
            .iter()
            .any(|capability| match capability {
                ExtensionCapability::DownloadFile(capability) => capability.allows(desired_url),
                _ => false,
            });

        if !is_allowed {
            bail!(
                "Extension {} does not have permission to download from '{}'",
                self.manifest.id,
                desired_url
            );
        }
        Ok(())
    }

    pub fn grant_npm(&self, package_name: &str) -> Result<()> {
        let is_allowed = self
            .granted_capabilities
            .iter()
            .any(|capability| match capability {
                ExtensionCapability::NpmInstallPackage(capability) => {
                    capability.allows(package_name)
                }
                _ => false,
            });

        if !is_allowed {
            bail!(
                "Extension {} does not have permission to npm install package '{}'",
                self.manifest.id,
                package_name
            );
        }
        Ok(())
    }
}

pub trait LanguageModelProvider: 'static {
    fn id(&self) -> LanguageModelProviderId;
    fn name(&self) -> LanguageModelProviderName;
    fn icon(&self) -> IconOrSvg { ... }
    fn default_model(&self, cx: &App) -> Option<Arc<dyn LanguageModel>>;
    fn default_fast_model(&self, cx: &App) -> Option<Arc<dyn LanguageModel>>;
    fn provided_models(&self, cx: &App) -> Vec<Arc<dyn LanguageModel>>;
    fn recommended_models(&self, _cx: &App) -> Vec<Arc<dyn LanguageModel>> {
        Vec::new()
    }
    fn is_authenticated(&self, cx: &App) -> bool;
    fn authenticate(&self, cx: &mut App) -> Task<Result<()>>;
}

pub fn available_models(&self, cx: &App) -> impl Iterator<Item = Arc<dyn LanguageModel>> {
    self.providers
        .values()
        .filter(|provider| provider.is_authenticated(cx))
        .flat_map(|provider| provider.provided_models(cx))
}

fn select_model(&self, selected_model: &SelectedModel, cx: &App) -> Option<ConfiguredModel> {
    let provider = self.provider(&selected_model.provider)?;
    let model = provider
        .provided_models(cx)
        .iter()
        .find(|model| model.id() == selected_model.model)?
        .clone();
    Some(ConfiguredModel { provider, model })
}

